function.body:
TYPE RECORD IS REF CURSOR;
  Cur_RveDetailConcept            RECORD;
  Cur_Parameter                   RECORD;

  v_client_id                     VARCHAR2(32);
  v_user_id                       VARCHAR2(32);

  v_ResultStr                     VARCHAR2(2000) := '';
  v_count                         INTEGER;
  v_BpartnerID			VARCHAR2(32);      
  v_CPeriodID			VARCHAR2(32);      
  v_telecomm_dailing_id		VARCHAR2(32);      
   v_n_insertions 	 NUMBER;	--OBTG:NUMBER--
  v_Message 			VARCHAR2(2000):='';

BEGIN
  --  Update AD_PInstance
  DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || PInstance_ID) ;
  v_ResultStr := 'PInstanceNotFound';
  AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'Y', NULL, NULL) ;

  BEGIN --BODY

	-- Get Parameters
	v_ResultStr := 'ReadingParameters';
	v_n_insertions := 0; 

   FOR Cur_Parameter IN
      (SELECT i.Record_ID,
              i.AD_User_ID, 
              i.AD_Client_ID,
              i.AD_Org_ID                    
       FROM AD_PInstance i      
       WHERE i.AD_PInstance_ID = PInstance_ID)
    LOOP

      v_telecomm_dailing_id := Cur_Parameter.record_id;	  
      v_client_id := Cur_Parameter.ad_client_id;
      v_user_id := Cur_Parameter.ad_user_id;     

    END LOOP; -- Get Parameter


	insert into sprbi_biometric( sprbi_biometric_id, ad_client_id, ad_org_id, isactive, 
	created, createdby, updated, updatedby, datemovement, entryhour_m, 
	exithour_m, entryhour_a, exithour_a, state, c_bpartner_id, processed, 
	identify, em_sscmu_location_marking, em_ssptdl_geolocation, 
	em_ssptdl_remote_dialing
	)

	SELECT ssptdl_telecomm_dialing_id, ad_client_id, ad_org_id, isactive, 
	now() as created, v_user_id as createdby, now() as updated, v_user_id as updatedby, datemovement,
	now() as entryhour_m,
	exithour_m, entryhour_a, exithour_a, state, c_bpartner_id, processed, 
	identify, location_marking, geolocation,'Y' as remote_dialing
	FROM ssptdl_telecomm_dialing
	where ssptdl_telecomm_dialing_id = v_telecomm_dailing_id;

	update ssptdl_telecomm_dialing
	set state='PR',Entryhour_M=now()
	where ssptdl_telecomm_dialing_id = v_telecomm_dailing_id;



    v_Message := '@RowsDeleted@: ' || v_n_insertions || '.';
    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished ' || v_Message) ;
    AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 1, v_Message) ;
    RETURN;

  END; --END BODY
  EXCEPTION
  WHEN OTHERS THEN
    v_ResultStr:= '@ERROR=' || SQLERRM;
    DBMS_OUTPUT.PUT_LINE(v_ResultStr) ;
    AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, v_ResultStr) ;
    RETURN;
END SSPTDL_PROCESS_DIALING
